function effectiveDate(e){ if(e.activity!=='sleep'&&e.activity!=='sleepDuration') return e.date; if(e.sleepDate) return e.sleepDate; if(e.end && e.start && e.end < e.start) return e.date; return e.date; }
function entries(date=todayKey(), id=null){ return state.log.filter(e=>effectiveDate(e)===date && (!id || e.activity===id)); }
