function requirementMet(id,date=todayKey()){ const legacySleep=id==='sleep'; if(!legacySleep) id=normalizeActivityId(id); if(!state.activitySettings[id]?.streakEnabled) return false; if(id==='sleepDuration'||legacySleep) return sleepMet(date, legacySleep?'sleep':'sleepDuration'); if(id==='socialMediaFree') { const es=entries(date,id); if(es.at(-1)?.mode==='usage') return num(es.at(-1).value)<=dailyRequirementFor(id); } return valueFor(id,date)>=dailyRequirementFor(id); }
function protectionUsed(id,date){ return !!state.streakData.manualProtection?.[id]?.[date]; }
