function maybeAutoProtect(id,date){ const s=state.activitySettings[id]; if(s?.autoProtection && canProtect(id,date)){ state.streakData.manualProtection[id] ||= {}; state.streakData.manualProtection[id][date]=true; return true; } return false; }
