function enabledStreakIds(){ return Object.keys(activities).filter(id=>state.activitySettings[id]?.enabled && state.activitySettings[id]?.streakEnabled); }
function weekStart(date=todayKey()){ const d=new Date(`${date}T12:00:00Z`), dow=d.getUTCDay(), off=state.settings.weekStarts==='sunday'?dow:(dow+6)%7; d.setUTCDate(d.getUTCDate()-off); return d.toISOString().slice(0,10); }
