function deleteEntry(id){ state.log=state.log.filter(e=>e.id!==id); recalc(); render(); }
function editEntry(id){ const e=state.log.find(x=>x.id===id); if(!e) return; const v=prompt('Ny værdi', e.value ?? e.hours ?? 0); if(v===null) return; if(e.activity==='sleepDuration') e.hours=num(v); else e.value=num(v); recalc(); render(); }
function compareLastWeek(id){ const now=periodValue(id), last=periodValue(id,day(-7)); if(!last && !now) return 'Ingen sammenligning endnu'; const pct= last ? Math.round((now-last)/last*100) : 100; return pct>=0?`+${pct}% mod sidste uge`:`${pct}% mod sidste uge`; }
function renderVersion(){ const label=$('#app-version-label'), build=$('#app-build-label'); if(label) label.textContent=`OneUp Prototype · v${APP_VERSION}`; if(build) build.textContent=APP_BUILD_LABEL; document.querySelectorAll('link[rel="stylesheet"][href^="styles.css"]').forEach(el=>el.href=`styles.css?v=${APP_VERSION}`); document.querySelectorAll('script[src^="script.js"]').forEach(el=>el.src=`script.js?v=${APP_VERSION}`); }
function renderToday(){ const score=oneUpScore(), ids=enabledStreakIds(), infos=ids.map(id=>streakInfo(id)), weeklyDone=ids.reduce((sum,id)=>sum+weeklyConsistency(id).done,0), enabled=activeActivityIds(); $('#oneup-score').textContent=score; $('#today-points').textContent=fmt(state.history[todayKey()].totalPoints); $('#goals-met').textContent=`${enabled.filter(id=>activityPercent(id)>=100).length}/${enabled.length}`; $('#today-streak').textContent=`${streak()} dage`; $('#encouragement').textContent= score>=90?'Du har allerede slået stærkt igennem i dag.':score>=60?'Du er godt i gang – hold rytmen roligt.':'Start med én lille handling. Det tæller.'; const cs=$('#consistency-section'); if(cs) cs.innerHTML=`<div><p class="eyebrow">Konsistens slår perfektion.</p><h3>Konsistensscore: ${consistencyScore()}/100</h3><p>Én god dag mere bygger videre på rytmen.</p></div><div class="mini-metrics"><span>Længste aktive streak: <b>${bestStreak()}</b></span><span>Aktive streaks: <b>${infos.filter(i=>i.current>0).length}/${ids.length}</b></span><span>Ugens gennemførte dage: <b>${weeklyDone}</b></span></div>`; const summary=$('#today-goal-summary'); if(summary) summary.textContent=enabled.length?`${enabled.filter(id=>activityPercent(id)>=100).length} af ${enabled.length} aktive mål er nået i dag. Detaljer ligger under Aktiviteter og Udvikling.`:'Ingen aktive mål endnu. Vælg aktiviteter for at begynde.'; }
function checkboxRow(attrs, label, extraClass=''){ return `<label class="checkbox-row${extraClass?` ${extraClass}`:''}"><input ${attrs} type="checkbox"><span>${label}</span></label>`; }
function renderActivities(){ $('#activity-manager').innerHTML=Object.entries(activities).map(([id,a])=>{const s=state.activitySettings[id]; return `<article class="card"><div class="card-head"><h3>${a.icon} ${a.name}</h3>${checkboxRow(`data-toggle="${id}" ${s.enabled?'checked':''}`, 'Aktiv')}</div><p>I dag: ${fmt(valueFor(id))} ${a.unit}</p><label class="field">Personligt mål<input data-goal="${id}" type="number" value="${goalFor(id)}" /></label><div class="streak-settings">${checkboxRow(`data-streak-enabled="${id}" ${s.streakEnabled?'checked':''}`, 'Streak til')}<label class="field">Dagligt streak-krav<input data-daily-req="${id}" type="number" value="${dailyRequirementFor(id)}"></label><label class="field">Ugentligt konsistensmål (dage)<input data-weekly-goal="${id}" type="number" min="1" max="7" value="${s.weeklyGoal}"></label>${checkboxRow(`data-protection-enabled="${id}" ${s.protectionEnabled?'checked':''}`, 'Streak-beskyttelse')}${checkboxRow(`data-auto-protection="${id}" ${s.autoProtection?'checked':''}`, 'Brug automatisk streak-beskyttelse')}${id==='sleep'?sleepSettingsHtml(s):''}</div>${a.auto?'<p class="muted">Automatisk registrering kommer senere.</p>':''}<div class="entry-controls">${entryControls(id)}</div></article>`}).join(''); renderEntryList(); }
function sleepSettingsHtml(s){ const c=s.sleepCriteria||{}; return `<div class="sleep-grid"><p><b>Søvnkriterier</b></p>${[['duration','Minimum søvnlængde'],['interval','Ønsket interval'],['bedtime','Sengetid i vindue'],['wake','Opvågning i vindue'],['screenfree','Skærmfri tid før søvn']].map(([k,l])=>checkboxRow(`data-sleep-criterion="${k}" ${c[k]?'checked':''}`, l)).join('')}<label class="field">Minimum timer<input data-sleep-field="sleepMinHours" type="number" step="0.25" value="${s.sleepMinHours}"></label><label class="field">Interval min/max<input data-sleep-field="sleepMinInterval" type="number" step="0.25" value="${s.sleepMinInterval}"><input data-sleep-field="sleepMaxInterval" type="number" step="0.25" value="${s.sleepMaxInterval}"></label><label class="field">Sengetid ± minutter<input data-sleep-field="bedtimeTarget" type="time" value="${s.bedtimeTarget}"><input data-sleep-field="bedtimeTolerance" type="number" value="${s.bedtimeTolerance}"></label><label class="field">Opvågning ± minutter<input data-sleep-field="wakeTarget" type="time" value="${s.wakeTarget}"><input data-sleep-field="wakeTolerance" type="number" value="${s.wakeTolerance}"></label></div>`; }
function entryControls(id){ if(id==='sleep') return '<input data-sleep-start type="time" value="22:30"><input data-sleep-end type="time" value="06:30"><button data-add="sleep">Registrér søvn</button>'; if(id==='meditation') return '<button data-add="meditation" data-value="5">5</button><button data-add="meditation" data-value="10">10</button><button data-add="meditation" data-value="20">20</button><input data-input="meditation" type="number" placeholder="Min"><button data-add="meditation">Gem</button>'; if(id==='running'||id==='cycling') return `<input data-input="${id}" type="number" placeholder="Kilometer"><button data-add="${id}">Gem</button>`; return `<input data-input="${id}" type="number" placeholder="${activityMeta(id).unit}"><button data-add="${id}">Gem</button>`; }
function renderEntryList(){ $('#entry-list').innerHTML=entries().map(e=>`<li>${activityMeta(e.activity).name}: ${fmt(e.value??e.hours)} ${activityMeta(e.activity).unit||''} <button data-edit-entry="${e.id}">Ret</button> <button data-delete-entry="${e.id}">Slet</button></li>`).join('')||'<li>Ingen registreringer i dag endnu.</li>'; }
function renderCompetition(){ const type=$('#competition-type'); if(!type.options.length) ['Procent af eget mål','Længste aktuelle streak','Højeste Konsistensscore','Flest gennemførte dage denne uge','Højeste procent af personligt ugemål','Samlede point'].forEach(x=>type.add(new Option(x,x))); const ids=enabledStreakIds(), weekDone=ids.reduce((s,id)=>s+weeklyConsistency(id).done,0), metric=type.value||'Procent af eget mål'; const you=metric.includes('streak')?streak():metric.includes('Konsistens')?consistencyScore():metric.includes('uge')?weekDone:oneUpScore(); const rows=[['Dig',you,'+8',true],['Amina',Math.max(0,you-3),'+4',true],['Jonas',Math.max(0,you-10),'-2',false],['Sofie',Math.max(0,you-15),'+11',true]]; $('#leaderboard').innerHTML=rows.sort((a,b)=>b[1]-a[1]).map((r,i)=>`<li><b>${i+1}. ${r[0]}</b><span>${r[1]} · ${r[3]?'↗':'↘'} ${r[2]}</span></li>`).join(''); $('#self-summary').innerHTML=[`Nuværende streak mod tidligere rekord: ${streak()} / ${bestStreak()}`,`Denne uges konsistens mod sidste uge: ${weeklyTrend(0)}% / ${weeklyTrend(1)}%`,`Denne måned mod forrige måned: ${monthConsistency(0)}% / ${monthConsistency(1)}%`,`Bedste 28-dages periode: ${best28()}%`,`En enkelt pause sletter ikke din fremgang.`].map(t=>`<article class="card">${t}</article>`).join(''); $('#self-ranking').innerHTML=ids.map((id,i)=>`<li><b>${i+1}. ${activityMeta(id).name}</b><span>${weeklyConsistency(id).percent}% af eget ugemål</span></li>`).join(''); }
function weeklyTrend(w){ const ids=enabledStreakIds(); if(!ids.length) return 0; return Math.round(ids.reduce((s,id)=>s+[0,1,2,3,4,5,6].filter(d=>dayComplete(id,day(-(w*7+d)))).length/7*100,0)/ids.length); }
function monthConsistency(m){ const ids=enabledStreakIds(); if(!ids.length) return 0; return Math.round(ids.reduce((s,id)=>s+[...Array(28)].filter((_,i)=>dayComplete(id,day(-(m*28+i)))).length/28*100,0)/ids.length); }
function best28(){ let best=0; for(let o=0;o<120;o++) best=Math.max(best,monthConsistency(Math.floor(o/28))); return best; }
function weeklyScores(){ return [0,1,2,3,4,5,6,7].map(w=>[0,1,2,3,4,5,6].reduce((s,d)=>s+num(state.history[day(-(w*7+d))]?.totalPoints),0)).sort((a,b)=>b-a); }
function renderDevelopment(){ const filter=$('#development-filter'); if(filter.options.length===1) Object.entries(activities).forEach(([id,a])=>filter.add(new Option(a.name,id))); $('#bars-7').innerHTML=[-6,-5,-4,-3,-2,-1,0].map(o=>{const d=day(o), val=filter.value==='all'?oneUpScore(d):activityPercent(filter.value,d); return `<div><span style="height:${val}%"></span><small>${d.slice(5)}</small></div>`}).join(''); $('#bars-4').innerHTML=[3,2,1,0].map(w=>`<div><span style="height:${weeklyTrend(w)}%"></span><small>Uge ${4-w}</small></div>`).join(''); const ids=enabledStreakIds(), infos=ids.map(id=>streakInfo(id)), best=infos.slice().sort((a,b)=>monthConsistencyFor(b.id)-monthConsistencyFor(a.id))[0], need=infos.slice().sort((a,b)=>monthConsistencyFor(a.id)-monthConsistencyFor(b.id))[0]; const sec=$('#streak-development'); if(sec) sec.innerHTML=`<h3>Streaks og konsistens</h3><div class="card-list">${infos.map(i=>`<article class="card"><h4>${activityMeta(i.id).icon} ${activityMeta(i.id).name}</h4><p>Nuværende: ${i.current} dage · Længste: ${i.best} dage · Senest aktiv: ${i.lastActiveDate||'ingen endnu'}</p><p>Uge: ${i.weekly.done}/${i.weekly.goal} dage (${i.weekly.percent}%) · ${i.weekly.onTrack?'Du er på kurs til ugens mål.':'Begynd igen i dag.'}</p><div class="week-dots">${i.weekly.dates.map(d=>`<span class="${dayComplete(i.id,d)?'done':''}">${d.slice(8)}</span>`).join('')}</div></article>`).join('')}</div><p class="info-box">Seneste 4 ugers konsistens vises ovenfor. Bedste stabilitet: ${best?activityMeta(best.id).name:'ingen endnu'}. Mest brug for kontinuitet: ${need?activityMeta(need.id).name:'ingen endnu'}.</p>`; $('#weekly-summary').innerHTML=['Konsistens slår perfektion.','Én god dag mere bygger videre på rytmen.','En enkelt pause sletter ikke din fremgang.'].map(t=>`<article class="card">${t}</article>`).join(''); }
function monthConsistencyFor(id){ return Math.round([...Array(28)].filter((_,i)=>dayComplete(id,day(-i))).length/28*100); }
function renderProfile(){
  migrateProfileFields();
  const p=state.profile, units=state.settings.units==='imperial'?'imperial':'metric', height=cmToFeetInches(p.heightCm), weightLb=p.weightKg?kgToLb(p.weightKg).toFixed(1):'';
  const metricHeight=`<label class="field">Højde<div class="unit-input"><input name="heightCm" type="number" inputmode="decimal" min="50" max="250" step="0.1" value="${p.heightCm||''}"><span>cm</span></div></label>`;
  const imperialHeight=`<div class="field"><span>Højde</span><div class="inline-fields"><label class="unit-input"><input name="heightFeet" type="number" inputmode="numeric" min="1" max="8" step="1" value="${p.heightCm?height.feet:''}"><span>fod</span></label><label class="unit-input"><input name="heightInches" type="number" inputmode="numeric" min="0" max="11" step="1" value="${p.heightCm?height.inches:''}"><span>tommer</span></label></div></div>`;
  const metricWeight=`<label class="field">Vægt<div class="unit-input"><input name="weightKg" type="number" inputmode="decimal" min="20" max="350" step="0.1" value="${p.weightKg||''}"><span>kg</span></div></label>`;
  const imperialWeight=`<label class="field">Vægt<div class="unit-input"><input name="weightLb" type="number" inputmode="decimal" min="44" max="770" step="0.1" value="${weightLb}"><span>lb</span></div></label>`;
  $('#profile-form').innerHTML=`
    <p class="required-note">* Obligatorisk felt</p><p id="profile-message" class="muted" aria-live="polite"></p>
    <fieldset class="profile-section"><legend>Grundlæggende</legend><label class="field">Navn eller kaldenavn *<input id="profile-name" name="name" type="text" required aria-required="true" oninvalid="this.setCustomValidity('Skriv dit navn eller kaldenavn.')" oninput="this.setCustomValidity('')" value="${escapeHtml(p.name||'')}"></label><label class="field">Fødselsdato<input name="birthDate" type="date" min="1900-01-01" max="${todayKey()}" value="${p.birthDate||''}"></label>${p.legacyBirthYear&&!p.birthDate?`<p class="soft-note">Vælg din fulde fødselsdato. Dit tidligere fødselsår var ${escapeHtml(p.legacyBirthYear)}.</p>`:''}<label class="field">Biologisk køn<select name="biologicalSex"><option value="" ${!p.biologicalSex?'selected':''}>Ikke angivet</option><option value="female" ${p.biologicalSex==='female'?'selected':''}>Kvinde</option><option value="male" ${p.biologicalSex==='male'?'selected':''}>Mand</option></select></label></fieldset>
    <fieldset class="profile-section"><legend>Mål og enheder</legend><div class="field"><span>Enheder</span><div class="unit-choice"><button type="button" data-units="metric" class="${units==='metric'?'active':''}" aria-pressed="${units==='metric'}"><b>Europæiske</b><small>cm · kg · km</small></button><button type="button" data-units="imperial" class="${units==='imperial'?'active':''}" aria-pressed="${units==='imperial'}"><b>Amerikanske</b><small>ft/in · lb · miles</small></button></div></div>${units==='imperial'?imperialHeight:metricHeight}${units==='imperial'?imperialWeight:metricWeight}</fieldset>
    <fieldset class="profile-section"><legend>Placering og sprog</legend><label class="field">Bopælsland<select name="countryCode">${countryOptions(p.countryCode||'')}</select></label>${p.country&&!p.countryCode?`<p class="soft-note">Tidligere landværdi er bevaret: ${escapeHtml(p.country)}</p>`:''}<label class="field">Sprog<select name="language"><option value="da" ${(p.language||state.settings.language||'da')==='da'?'selected':''}>Dansk</option><option value="en" ${(p.language||state.settings.language)==='en'?'selected':''}>English</option></select></label></fieldset>
    <button type="submit">Gem profil</button>`;
  $('#settings-form').innerHTML=['vibration','sounds','voice'].map(k=>checkboxRow(`data-setting="${k}" ${state.settings[k]?'checked':''}`, k)).join('')+'<label class="field">Uge starter<select data-setting="weekStarts"><option value="monday">Mandag</option><option value="sunday">Søndag</option></select></label>';
}
function render(){ recalcSilently(); recalcCompetitions(); renderVersion(); renderToday(); renderActivities(); renderCompetition(); renderCompetitionSystem(); renderDevelopment(); renderProfile(); bindDynamic(); }
function recalcSilently(){ Object.values(state.history).forEach(r=>{r.activityPoints={};r.totalPoints=0}); state.log.forEach(e=>{const d=effectiveDate(e); const r=state.history[d] ||= {date:d,activityPoints:{}}; const p=pointsForEntry(e); r.activityPoints[e.activity]=(r.activityPoints[e.activity]||0)+p;}); Object.entries(state.history).forEach(([d,r])=>{r.totalPoints=Object.values(r.activityPoints||{}).reduce((s,v)=>s+num(v),0); r.oneUpScore=oneUpScore(d);}); state.points=Object.values(state.history).reduce((s,r)=>s+num(r.totalPoints),0); }
function bindDynamic(){ $$('[data-units]').forEach(b=>b.onclick=()=>{ saveProfileDraft(); state.settings.units=b.dataset.units; persist(); renderProfile(); bindDynamic(); }); $$('[data-nav]').forEach(b=>b.onclick=()=>{ if(b.dataset.nav==='competition') selectedCompetitionId=null; if(b.dataset.nav==='today') selectedCompetitionId=null; showPage(b.dataset.nav); }); $$('[data-toggle]').forEach(el=>el.onchange=()=>{state.activitySettings[el.dataset.toggle].enabled=el.checked; persist(); render();}); $$('[data-goal]').forEach(el=>el.onchange=()=>{state.activitySettings[el.dataset.goal].goal=num(el.value); persist(); render();}); $$('[data-daily-req]').forEach(el=>el.onchange=()=>{state.activitySettings[el.dataset.dailyReq].dailyRequirement=num(el.value); persist(); render();}); $$('[data-weekly-goal]').forEach(el=>el.onchange=()=>{state.activitySettings[el.dataset.weeklyGoal].weeklyGoal=clamp(num(el.value),1,7); persist(); render();}); $$('[data-streak-enabled]').forEach(el=>el.onchange=()=>{state.activitySettings[el.dataset.streakEnabled].streakEnabled=el.checked; persist(); render();}); $$('[data-protection-enabled]').forEach(el=>el.onchange=()=>{state.activitySettings[el.dataset.protectionEnabled].protectionEnabled=el.checked; persist(); render();}); $$('[data-auto-protection]').forEach(el=>el.onchange=()=>{state.activitySettings[el.dataset.autoProtection].autoProtection=el.checked; persist(); render();}); $$('[data-sleep-criterion]').forEach(el=>el.onchange=()=>{state.activitySettings.sleep.sleepCriteria[el.dataset.sleepCriterion]=el.checked; persist(); render();}); $$('[data-sleep-field]').forEach(el=>el.onchange=()=>{state.activitySettings.sleep[el.dataset.sleepField]=el.type==='number'?num(el.value):el.value; persist(); render();}); $$('[data-add]').forEach(b=>b.onclick=()=>manualAdd(b.dataset.add,b)); $$('[data-quick]').forEach(b=>b.onclick=()=>showPage('activities')); $$('[data-delete-entry]').forEach(b=>b.onclick=()=>deleteEntry(b.dataset.deleteEntry)); $$('[data-edit-entry]').forEach(b=>b.onclick=()=>editEntry(b.dataset.editEntry)); }
function manualAdd(id,b){ if(id==='sleepDuration'){ const start=$('[data-sleep-start]').value, end=$('[data-sleep-end]').value, [sh,sm]=start.split(':').map(Number), [eh,em]=end.split(':').map(Number); let h=(eh+em/60)-(sh+sm/60); if(h<0) h+=24; addEntry(id,{value:h,hours:h,start,end,sleepDate:todayKey()}); return; } const input=$(`[data-input="${id}"]`); addEntry(id,{value:num(b.dataset.value ?? input?.value), distance:num($(`[data-distance="${id}"]`)?.value), mode:id==='breathing'?document.querySelector('input[name="breathing-mode"]:checked')?.value:undefined}); }

function activeActivityIds(){ return Object.keys(activities).filter(id=>state.activitySettings[id]?.enabled); }
function userName(){ return state.profile.nickname || 'Dig'; }
function demoParticipants(){ return [{id:'amina',name:'Amina',demo:true,friend:true},{id:'jonas',name:'Jonas',demo:true,friend:true},{id:'sofie',name:'Sofie',demo:true,friend:false}]; }
function defaultWeights(ids){ if(!ids.length) return {}; const base=Math.floor(10000/ids.length)/100, weights=Object.fromEntries(ids.map(id=>[id,base])); weights[ids[0]]=Math.round((100-base*(ids.length-1))*100)/100; return weights; }
function sanitizeActivityIds(ids){ return [...new Set((ids||[]).map(id=>id==='steps'?'dailyStepTarget':normalizeActivityId(id)).filter(id=>allActivities[id]))]; }
function isDeprecatedActivity(id){ return !!deprecatedActivities[normalizeActivityId(id)]; }
function activityMeta(id){ return allActivities[normalizeActivityId(id)] || {id,name:id,icon:'•',description:''}; }

const periodLabels={daily:'pr. dag',averageDaily:'gennemsnit pr. dag',weekly:'pr. uge',competition:'hele konkurrencen',day:'pr. dag',week:'pr. uge'};
const metricUnits={steps:'skridt',sets:'sæt',minutes:'minutter',kilometers:'km',breathingActivities:'aktiviteter',workouts:'træningspas',hours:'timer'};
function baseGoalConfig(id){
  id=normalizeActivityId(id);
  const s=state?.activitySettings?.[id]||{}, a=activityMeta(id);
  if(isDeprecatedActivity(id)) return {activityId:id,metric:'legacy',period:'daily',target:num(s.goal||1),bonusTarget:null,unit:a.unit||'',comparisonMode:'moreIsBetter',scoringMethod:'moreIsBetter',legacyDefault:true,deprecated:true,migrationNotice:'Denne aktivitet bruges ikke længere i nye konkurrencer.'};
  if(id==='mostSteps') return {activityId:id,metric:'steps',unit:'skridt',period:'averageDaily',target:0,bonusTarget:null,comparisonMode:'ranking',scoringMethod:'ranking',legacyDefault:true,complete:true};
  if(id==='dailyStepTarget') return {activityId:id,metric:'steps',unit:'skridt',period:'daily',target:num(s.goal||8000),bonusTarget:null,comparisonMode:'completedDays',scoringMethod:'completedDays',legacyDefault:true};
  if(id==='bedtime') return {activityId:id,metric:'time',unit:'kl.',target:num(s.goal||22.25),bonusTarget:null,comparisonMode:'earlierThanTarget',scoringMethod:'earlierThanTarget',period:'daily',legacyDefault:true};
  if(id==='breathing') return {activityId:id,metric:'breathingActivities',unit:'aktiviteter',target:Math.max(1,Math.ceil(num(s.goal||10)/10)),bonusTarget:null,comparisonMode:'moreIsBetter',scoringMethod:'moreIsBetter',period:'daily',roundsPerActivity:10,migrationNotice:num(s.goal||0)>4?'Dette mål er blevet tilpasset til 10 runder pr. aktivitet. Kontrollér målet.':''};
  if(id==='running'||id==='cycling') return {activityId:id,metric:'kilometers',unit:'km',period:'weekly',target:num(s.goal||a.goal||1),bonusTarget:null,comparisonMode:'moreIsBetter',scoringMethod:'moreIsBetter',legacyDefault:true};
  if(id==='socialMediaFree') return {activityId:id,metric:'minutes',unit:'minutter',period:'daily',target:num(s.goal||60),bonusTarget:null,comparisonMode:'lessIsBetter',scoringMethod:'lessIsBetter',legacyDefault:true};
  return {activityId:id,metric:a.unit==='skridt'?'steps':'minutes',period:a.period==='week'?'weekly':'daily',target:num(s.goal||a.goal||1),bonusTarget:null,unit:a.unit||metricUnits.minutes,comparisonMode:'moreIsBetter',scoringMethod:'moreIsBetter',legacyDefault:true};
}
function normalizeGoalConfig(id,cfg={}){
  id=normalizeActivityId(id); const b=baseGoalConfig(id); const out={...b,...cfg,activityId:id};
  if(id==='breathing' && (out.metric==='rounds'||out.unit==='runder'||num(out.target)>4 && out.roundsPerActivity!==10)){ out.target=Math.max(1,Math.ceil(num(out.target)/10)); out.metric='breathingActivities'; out.unit='aktiviteter'; out.period='daily'; out.roundsPerActivity=10; out.migrationNotice='Dette mål er blevet tilpasset til 10 runder pr. aktivitet. Kontrollér målet.'; }
  if((id==='running'||id==='cycling') && out.metric && out.metric!=='kilometers'){ out.needsReconfiguration=true; out.migrationNotice='Skal konfigureres igen i kilometer'; out.metric='kilometers'; out.unit='km'; out.complete=false; }
  out.target=num(out.target); out.bonusTarget=out.bonusTarget===''?null:(out.bonusTarget==null?null:num(out.bonusTarget)); out.unit=out.unit||metricUnits[out.metric]||b.unit; out.period=id==='breathing'?'daily':(out.period||'daily'); out.comparisonMode=out.comparisonMode||'moreIsBetter'; if(id==='mostSteps'){ out.target=0; out.complete=true; out.comparisonMode='ranking'; out.scoringMethod='ranking'; return out; }
  if(id==='dailyStepTarget') out.comparisonMode='completedDays';
  if(id==='bedtime') out.comparisonMode='earlierThanTarget';
  if(id==='strength'){ out.metric='sets'; out.unit='sæt'; }
  if(id==='socialMediaFree') out.comparisonMode='lessIsBetter'; out.scoringMethod=out.comparisonMode==='lessIsBetter'?'lessIsBetter':(out.comparisonMode==='withinRange'?'withinRange':(out.comparisonMode==='earlierThanTarget'?'earlierThanTarget':'moreIsBetter'));
  const lowerBetter=id==='bedtime'||id==='socialMediaFree';
  out.bonusTarget=null;
  out.complete=!out.needsReconfiguration && (id==='mostSteps' || !!out.target);
  if(id==='breathing' && (!Number.isInteger(out.target)||out.target<1)) out.complete=false;
  return out;
}
function ensureCompetitionGoals(c){ c.activityGoals ||= {}; c.activities=sanitizeActivityIds(c.activities); c.activities.forEach(id=>{ c.activityGoals[id]=normalizeGoalConfig(id,c.activityGoals[id]); }); return c.activityGoals; }
function goalConfig(c,id){ return normalizeGoalConfig(id,(c.activityGoals||{})[id]); }
function scoreMoreIsBetter(value,target){ value=num(value); target=num(target)||1; return value<=target?clamp(value/target*100,0,100):100; }
function scoreLessIsBetter(value,target){ value=num(value); target=num(target)||1; return value<=target?100:clamp(100-(value-target)/target*100,0,100); }
function scoreEarlierThanTarget(value,target,tolerance=60){ value=num(value); target=num(target)||1; return value<=target?100:clamp(100-((value-target)/Math.max(1,num(tolerance)))*100,0,100); }
function scoreWithinRange(value,minimum,maximum,tolerance=0){ value=num(value); minimum=num(minimum); maximum=num(maximum); tolerance=num(tolerance); if(value>=minimum&&value<=maximum) return 100; const diff=value<minimum?minimum-value:value-maximum; return clamp(100-(diff/Math.max(1,tolerance||maximum||minimum))*100,0,100); }
function scoreConsistency(done,total,target){ const ratio=num(done)/Math.max(1,num(target)||num(total)||1); return scoreMoreIsBetter(ratio*100,100); }
function goalSummary(cfg){ cfg=normalizeGoalConfig(cfg.activityId,cfg); if(cfg.deprecated) return `${activityMeta(cfg.activityId).name}: Denne aktivitet bruges ikke længere i nye konkurrencer.`; if(cfg.needsReconfiguration) return cfg.migrationNotice||'Skal konfigureres igen.'; if(cfg.activityId==='mostSteps') return `Flest skridt · Måling: ${cfg.period==='competition'?'Flest skridt i hele konkurrenceperioden':cfg.period==='daily'?'Flest skridt pr. dag':'Højeste gennemsnit pr. dag'}`; if(cfg.activityId==='dailyStepTarget') return `Dagligt skridtmål · Mål: ${fmt(cfg.target)} skridt · Scoring: Antal dage med nået mål`; if(cfg.activityId==='bedtime') return `Sengetid · Mål: senest kl. ${timeLabel(cfg.target)} · Scoring: gennemført dag`; if(cfg.activityId==='breathing') return `Åndedrætsøvelser · Mål: ${fmt(cfg.target)} ${cfg.target===1?'aktivitet':'aktiviteter'} pr. dag · Svarende til ${fmt(cfg.target*10)} runder pr. dag`; if(cfg.activityId==='strength') return `Styrketræning · Mål: ${fmt(cfg.target)} sæt ${periodLabels[cfg.period]||cfg.period}`; if(cfg.activityId==='running'||cfg.activityId==='cycling') return `${activityMeta(cfg.activityId).name} · Mål: ${fmt(cfg.target)} km ${periodLabels[cfg.period]||cfg.period}`; if(cfg.activityId==='socialMediaFree') return `Tid på sociale medier · Mål: højst ${fmt(cfg.target)} minutter ${periodLabels[cfg.period]||cfg.period} · Jo mindre jo bedre`; if(cfg.activityId==='screenFreeBeforeBed') return `Skærmfri før sengetid · Mål: ${fmt(cfg.target)} minutter`; return `${activityMeta(cfg.activityId).name} · Mål: ${fmt(cfg.target)} ${cfg.unit} ${periodLabels[cfg.period]||cfg.period}`; }
function scoringLabelForGoal(cfg){ cfg=normalizeGoalConfig(cfg.activityId,cfg); return cfg.comparisonMode==='ranking'?'Rangliste normaliseret til 0-100':cfg.comparisonMode==='lessIsBetter'?'Mindre er bedre':cfg.comparisonMode==='completedDays'?'Dage med nået mål':cfg.comparisonMode==='earlierThanTarget'?'Til tiden':'Procent af mål'; }
function goalComplete(cfg){ return normalizeGoalConfig(cfg.activityId,cfg).complete; }
function newCompetitionGoalDefault(id) {
  const defaults = {
    strength: 1,
    breathing: 1,
    meditation: 10,
    screenFreeBeforeBed: 30,
    socialMediaFree: 60,
    running: 5,
    cycling: 10,
    dailyStepTarget: 8000
  };

  if (id === 'mostSteps') return 0;

  return defaults[id] ?? baseGoalConfig(id).target ?? 1;
}
function draftGoal(id) {
  competitionDraft.activityGoals ||= {};

  if (!competitionDraft.activityGoals[id]) {
    competitionDraft.activityGoals[id] = normalizeGoalConfig(id, {
      ...baseGoalConfig(id),
      target: newCompetitionGoalDefault(id),
      legacyDefault: false,
      complete: true,
      migratedFromLegacy: false,
      needsReconfiguration: false,
      migrationNotice: ''
    });
  }

  return competitionDraft.activityGoals[id];
}
function wizardIncompleteActivities(d){ return (d.activities||[]).filter(id=>!goalComplete((d.activityGoals||{})[id]||{activityId:id,target:0})); }

function periodGoalForCompetition(id,c,date=todayKey()){ const cfg=goalConfig(c,id), end=(c.endDate&&c.endDate<date)?c.endDate:date, days=dateRange(c.startDate||end,end).length||1; if(cfg.period==='competition') return cfg.target; if(cfg.period==='weekly') return cfg.target*Math.max(1,days/7); return cfg.target*days; }
function competitionPeriodValue(id,participant,c,date=todayKey()){ const end=(c.endDate&&c.endDate<date)?c.endDate:date; return dateRange(c.startDate||end,end).reduce((s,d)=>s+rawActivityValueForParticipant(id,participant,d),0); }
function activityChips(ids,limit=3){ const safe=sanitizeActivityIds(ids); const shown=safe.slice(0,limit).map(id=>{ const a=activityMeta(id); return `<span class="chip ${isDeprecatedActivity(id)?'deprecated':''}" title="${a.description}">${a.icon} ${a.name}${isDeprecatedActivity(id)?' (udgået)':''}</span>`; }).join(''); return shown+(safe.length>limit?`<span class="chip">+${safe.length-limit} aktiviteter</span>`:''); }
function createCompetition(cfg){ cfg={...cfg,type:normalizeCompetitionType(cfg.type)}; const ids=sanitizeActivityIds(cfg.activities||activeActivityIds()); ids.filter(id=>activities[id]).forEach(id=>{ state.activitySettings[id] ||= {...defaultActivitySettings()[id]}; state.activitySettings[id].enabled=true; }); const participants=cfg.type==='self'?[{id:currentUserId,name:userName()}]:[{id:currentUserId,name:userName()},...(cfg.participants||demoParticipants())]; const activityGoals=Object.fromEntries(ids.map(id=>[id,normalizeGoalConfig(id,(cfg.activityGoals||{})[id]||baseGoalConfig(id))])); const c={id:`comp-${Date.now()}-${Math.random().toString(16).slice(2)}`,name:cfg.name||'Ny konkurrence',type:cfg.type||'self',status:'active',creator:currentUserId,leaders:[currentUserId],participants,activities:ids,activityGoals,weighting:{mode:cfg.weightingMode||'equal',weights:cfg.weightingMode==='custom'?Object.fromEntries(ids.map(id=>[id,(cfg.weights||{})[id] ?? (id==='dailyStepTarget'?(cfg.weights||{}).steps:undefined) ?? defaultWeights(ids)[id]])):defaultWeights(ids)},scoringMethod:cfg.scoringMethod||'configuredGoals',startDate:cfg.startDate||todayKey(),endDate:cfg.endDate||day(6),changeLog:[],results:{},settings:{ruleChangeMode:'fromNow',hvrReady:true,coopGoal:cfg.type==='coop'},createdAt:new Date().toISOString()}; state.competitions.unshift(c); addCompetitionChange(c,'oprettede konkurrencen','-',c.name); recalcCompetitions(); persist(); return c; }
function isCompetitionLeader(c,uid=currentUserId){ return (c.leaders||[]).includes(uid); }
function addCompetitionChange(c,what,oldValue,newValue){ c.changeLog ||= []; c.changeLog.unshift({id:`chg-${Date.now()}-${Math.random().toString(16).slice(2)}`,at:new Date().toISOString(),leaderId:currentUserId,leaderName:userName(),what,oldValue,newValue,mode:'fromNow'}); }
function dateRange(start,end){ const out=[]; for(let d=start,guard=0; d<=end && guard<370; d=day(1,d),guard++) out.push(d); return out; }
function rawActivityValueForParticipant(id,participant,date){ const mine=valueFor(id,date); if(participant.id===currentUserId) return mine; const seed=participant.id.split('').reduce((s,ch)=>s+ch.charCodeAt(0),0)+(date||'').slice(-2)*7; const g=goalFor(id)||1; return Math.round(g*(.55+((seed%70)/100))); }
function sleepCompetitionScore(participant,date){ const base=rawActivityValueForParticipant('sleep',participant,date), g=goalFor('sleep')||8; const duration=Math.min(base/g*75,75), regularity=participant.id===currentUserId && requirementMet('sleep',date)?25:18; return clamp(duration+regularity,0,120); }
function activityEntryPoints(id,participant,date){ if(participant.id!==currentUserId) return Math.round(rawActivityValueForParticipant(id,participant,date)/Math.max(1,goalFor(id))*100); return entries(date,id).reduce((s,e)=>s+pointsForEntry(e),0); }
function baselineFor(id,participant,date){ return [7,8,9,10,11,12,13].reduce((s,o)=>s+rawActivityValueForParticipant(id,participant,day(-o,date)),0)/7 || 1; }
function competitionActivityScore(c,id,participant,date=todayKey()){ id=id==='steps'?'dailyStepTarget':normalizeActivityId(id); if(!allActivities[id]) return 0; ensureCompetitionGoals(c); const cfg=goalConfig(c,id), raw=competitionPeriodValue(id,participant,c,date), g=periodGoalForCompetition(id,c,date)||1; if(c.scoringMethod==='points') return activityEntryPoints(id,participant,date); if(c.scoringMethod==='baseline') return clamp(raw/baselineFor(id,participant,date)*100,0,100); if(c.scoringMethod==='raw') return raw; if(c.scoringMethod==='completedDays') return raw>=g?100:0; if(cfg.comparisonMode==='ranking') return normalizedRankingScore(c,id,participant,date); if(cfg.comparisonMode==='completedDays') return dailyCompletionScore(c,id,participant,date); if(cfg.comparisonMode==='lessIsBetter') return scoreLessIsBetter(raw,g,null); if(cfg.comparisonMode==='withinRange') return scoreWithinRange(raw,cfg.minimum||cfg.target,cfg.maximum||cfg.target,cfg.tolerance||0); if(id==='bedtime') return raw&&raw<=g?100:0; return scoreMoreIsBetter(raw,g,null); }
function dailyCompletionScore(c,id,participant,date=todayKey()){ const cfg=goalConfig(c,id), dates=dateRange(c.startDate||date,(c.endDate&&c.endDate<date)?c.endDate:date); const done=dates.filter(d=>rawActivityValueForParticipant(id,participant,d)>=num(cfg.target)).length; return clamp(done/Math.max(1,dates.length)*100,0,100); }
function normalizedRankingScore(c,id,participant,date=todayKey()){ const vals=(c.participants||[]).map(p=>competitionPeriodValue(id,p,c,date)); const max=Math.max(...vals,0); if(!max) return 0; return clamp(competitionPeriodValue(id,participant,c,date)/max*100,0,100); }
function weightedScore(c,participant,date=todayKey()){ const ids=sanitizeActivityIds(c.activities), weights=c.weighting?.mode==='custom'?c.weighting.weights:defaultWeights(ids); if(!ids.length) return 0; return Math.round(ids.reduce((s,id)=>s+competitionActivityScore(c,id,participant,date)*(weights[id]||0)/100,0)); }
function participantDays(c,p){ return dateRange(c.startDate, (c.endDate&&c.endDate<todayKey())?c.endDate:todayKey()).filter(d=>sanitizeActivityIds(c.activities).some(id=>rawActivityValueForParticipant(id,p,d)>=goalFor(id))).length; }
function participantStreak(c,p){ let n=0; for(let i=0;i<120;i++){ const d=day(-i); if(d<c.startDate) break; if(sanitizeActivityIds(c.activities).some(id=>rawActivityValueForParticipant(id,p,d)>=goalFor(id))) n++; else break; } return n; }
function competitionLeaderboard(c,sort='score',friendsOnly=false){ const rows=(c.participants||[]).filter(p=>!friendsOnly||p.friend||p.id===currentUserId).map(p=>{ const ids=sanitizeActivityIds(c.activities); const per=Object.fromEntries(ids.map(id=>[id,competitionActivityScore(c,id,p)])); const score=weightedScore(c,p), prev=weightedScore(c,p,day(-1)); return {participant:p,perActivity:per,score,change:score-prev,completedDays:participantDays(c,p),streak:participantStreak(c,p),consistency:participantDays(c,p)*10,baseline:Object.values(per).reduce((a,b)=>a+b,0)/(ids.length||1)}; }); const key=sort==='completedDays'?'completedDays':sort==='consistency'?'consistency':sort==='baseline'?'baseline':sanitizeActivityIds(c.activities).includes(sort)?null:'score'; return rows.sort((a,b)=> key?b[key]-a[key]:(b.perActivity[sort]||0)-(a.perActivity[sort]||0)).map((r,i)=>({...r,rank:i+1})); }
function recalcCompetitions(){ (state.competitions||[]).forEach(c=>{ c.activities=sanitizeActivityIds(c.activities); ensureCompetitionGoals(c); c.weighting ||= {mode:'equal',weights:defaultWeights(c.activities)}; if(c.status==='active' && c.endDate<todayKey()){ c.status='finished'; c.finalResults=competitionLeaderboard(c); } c.results={leaderboard:competitionLeaderboard(c),updatedAt:new Date().toISOString(),userScore:weightedScore(c,{id:currentUserId,name:userName()})}; }); }
function archiveCompetition(id){ const c=state.competitions.find(x=>x.id===id); if(c){ c.status='archived'; addCompetitionChange(c,'arkiverede konkurrencen',c.status,'archived'); persist(); render(); } }
function removeLeader(c,uid){ if((c.leaders||[]).length<=1) { alert('Der skal altid være mindst én leder. Udnævn en anden leder først.'); return false; } c.leaders=c.leaders.filter(id=>id!==uid); addCompetitionChange(c,'fjernede lederstatus',uid,'ikke leder'); persist(); render(); return true; }
function ensureCompetitionWizard(){ if($('#competition-wizard')) return; document.body?.insertAdjacentHTML?.('beforeend','<div id="competition-wizard" class="modal" hidden></div>'); }
function renderCompetitionSystem(){ const today=$('[data-page="today"]'); if(today && !$('#competition-home-section')) today.querySelector?.('.score-hero')?.insertAdjacentHTML?.('afterend','<div class="button-row hero-actions"><button id="start-new-competition" data-open-competition-creator>Start ny konkurrence</button></div><section id="competition-home-section"><h2>Igangværende konkurrencer</h2><div id="active-competition-cards"></div></section>'); const compPage=$('[data-page="competition"]'), system=$('#competition-system'); if(compPage && !system) compPage.insertAdjacentHTML?.('afterbegin','<section id="competition-system"></section>'); const target=$('#competition-system'); if(target && !$('#competition-detail')) target.innerHTML='<div class="button-row"><button id="start-new-competition-page" data-open-competition-creator>Start ny konkurrence</button><button class="secondary" id="show-all-competitions">Se alle konkurrencer</button></div><div id="competition-detail"></div><h3>Tidligere konkurrencer</h3><div id="archived-competitions" class="card-list"></div>'; ensureCompetitionWizard(); renderHomeCompetitionCards(); renderCompetitionDetail(); bindCompetitionButtons(); }
function competitionDaysLeft(c){ return Math.max(0,dateRange(todayKey(),c.endDate).length-1); }
function competitionStatusLine(c){ const days=competitionDaysLeft(c), score=c.results?.userScore||0; if(c.type==='self') return `${Math.max(0,score-92)} % bedre end sidste uge · ${days} dage tilbage`; if(isCoopCompetition(c)) return `Sammen mod målet · ${score} fælles point · ${days} dage tilbage`; const rank=(c.results?.leaderboard||[]).find(r=>r.participant.id===currentUserId)?.rank||'-'; return `Nr. ${rank} af ${(c.participants||[]).length} · ${score} point · ${days} dage tilbage`; }
function competitionHomeStatusLine(c){ const days=competitionDaysLeft(c); return `${competitionTypeLabel(c.type)} · ${days===1?'1 dag tilbage':`${days} dage tilbage`}`; }
function limitedHomeActivities(c,mapper,moreLabel){ const ids=sanitizeActivityIds(c.activities), rows=ids.slice(0,4).map(mapper).join(''); return rows+(ids.length>4?`<p class="home-more muted">+ ${ids.length-4} ${moreLabel}</p>`:''); }
function selfActivityWindowScore(c,id,offset=0){ const participant={id:currentUserId,name:userName()}, end=day(offset), cfg=goalConfig(c,id); const dates=[0,-1,-2,-3,-4,-5,-6].map(o=>day(o,end)).filter(d=>!c.startDate||d>=c.startDate); if(!dates.length) return 0; if(cfg.period==='weekly') return clamp(dates.reduce((s,d)=>s+rawActivityValueForParticipant(id,participant,d),0)/Math.max(1,num(cfg.target))*100,0,200); if(cfg.period==='competition') return dates.reduce((s,d)=>s+competitionActivityScore(c,id,participant,d),0)/dates.length; const done=dates.filter(d=>competitionActivityScore(c,id,participant,d)>=100 || rawActivityValueForParticipant(id,participant,d)>=num(cfg.target)).length; return done/dates.length*100; }
function homeSelfProgressRows(c){ const ids=sanitizeActivityIds(c.activities); if(!ids.length) return '<p class="muted">Klar til start.</p>'; return limitedHomeActivities(c,id=>{ const a=activityMeta(id), now=selfActivityWindowScore(c,id,0), prev=selfActivityWindowScore(c,id,-7), diff=Math.round(now-prev), abs=Math.abs(diff), cls=diff>0?'positive':diff<0?'negative':'neutral', icon=diff>0?'↗':diff<0?'↘':'→', text=abs<1?'På niveau med sidste uge':diff>0?`${abs} % bedre end sidste uge`:`${abs} % lavere end sidste uge`; return `<div class="home-activity-row ${cls}"><span class="home-activity-name">${a.icon} ${a.name}</span><span class="home-activity-status">${icon} ${text}</span></div>`; }, 'flere aktiviteter'); }
function homeVersusLeaderboard(c){ const lb=competitionLeaderboard(c), top=lb.slice(0,5), mine=lb.find(r=>r.participant.id===currentUserId); return `<div class="home-leaderboard"><h4>Top 5</h4><ol>${top.map(r=>`<li class="${r.participant.id===currentUserId?'you':''}"><span>${r.rank}. ${r.participant.name}</span><b>${r.score}</b></li>`).join('')}</ol>${mine&&mine.rank>5?`<p class="home-my-rank muted">Din placering: nr. ${mine.rank} · ${mine.score} point</p>`:''}</div>`; }
function coopSharedTarget(c,id,date=todayKey()){ const cfg=goalConfig(c,id); return num(cfg.sharedTarget ?? cfg.target ?? periodGoalForCompetition(id,c,date)); }
function coopActivityValue(c,id,date=todayKey()){ return (c.participants||[]).reduce((sum,participant)=>sum+competitionPeriodValue(id,participant,c,date),0); }
function coopProgressText(percent){ if(percent>=100) return 'Målet er nået 🎉'; if(percent>=90) return 'Næsten i mål'; if(percent>=50) return 'I er godt på vej'; return 'Godt i gang'; }
function homeCoopProgressRows(c){ const ids=sanitizeActivityIds(c.activities); if(!ids.length) return '<p class="muted">Klar til fælles start.</p>'; return limitedHomeActivities(c,id=>{ const a=activityMeta(id), value=coopActivityValue(c,id), target=Math.max(1,coopSharedTarget(c,id)), percent=Math.round(value/target*100), visual=clamp(percent,0,100); return `<div class="home-coop-row"><div><b>${a.icon} ${a.name}</b><span>${fmt(value)} af ${fmt(target)}</span></div><strong>${percent} %</strong><div class="progress home-progress"><span style="width:${visual}%"></span></div><p class="muted">${coopProgressText(percent)}</p></div>`; }, 'flere fælles mål'); }
function competitionHomeCard(c){ const body=isCoopCompetition(c)?homeCoopProgressRows(c):c.type==='versus'?homeVersusLeaderboard(c):homeSelfProgressRows(c); return `<article class="card competition-card home-competition-card"><div class="card-head"><div><h3>${c.name}</h3><p class="muted">${competitionHomeStatusLine(c)}</p></div></div><div class="home-competition-body">${body}</div><div class="button-row"><button data-open-comp="${c.id}">Åbn hele konkurrencen</button></div></article>`; }
function competitionDetailCard(c){ const collapsed=state.competitionUi.collapsed[c.id] ?? false, leaders=(c.leaders||[]).map(id=>(c.participants||[]).find(p=>p.id===id)?.name||id).join(', '); const lb=competitionLeaderboard(c).slice(0,4); return `<article class="card competition-card ${collapsed?'collapsed':''}"><div class="card-head"><div><h3>${c.name}</h3><p class="muted">${competitionTypeLabel(c.type)} · ${competitionStatusLine(c)}</p></div><button class="secondary" data-toggle-comp="${c.id}">${collapsed?'Åbn':'Fold sammen'} ▾</button></div>${collapsed?'':`<div class="chip-row">${activityChips(c.activities)}</div><p><b>Konkurrenceledere:</b> ${leaders} <span class="leader-badge">Leder</span></p><p><b>Periode:</b> ${c.startDate} – ${c.endDate}</p><p><b>Scoring:</b> ${scoreLabel(c.scoringMethod)} · <b>Vægtning:</b> ${weightLabel(c)}</p>${isCoopCompetition(c)?'<p class="info-box"><b>Fælles fremdrift:</b> Deltagerne samarbejder om at nå et fælles mål. Alles aktivitet tæller med i jeres samlede bidrag.</p>':`<ol class="leaderboard compact">${lb.map(r=>`<li class="${r.participant.id===currentUserId?'you':''}"><b>${r.rank}. ${r.participant.name}</b><span>${r.score} · ${r.change>=0?'↗':'↘'} ${Math.abs(r.change)}</span></li>`).join('')}</ol>`}<p><b>${isCoopCompetition(c)?'Jeres samlede bidrag':'Din fremgang'}:</b> ${isCoopCompetition(c)?'Sammen mod målet med fælles fremdrift.':selfProgressText(c)}</p><div class="button-row"><button data-open-comp="${c.id}">Åbn hele konkurrencen</button>${isCompetitionLeader(c)?'<button class="secondary" data-leader-tools="'+c.id+'">Lederfunktioner</button>':''}</div>`}</article>`; }
function competitionCard(c,full=false){ return full?competitionDetailCard(c):competitionHomeCard(c); }
function renderHomeCompetitionCards(){ const el=$('#active-competition-cards'); if(!el) return; const active=(state.competitions||[]).filter(c=>c.status==='active'); el.innerHTML=active.length?active.slice(0,3).map(c=>competitionCard(c)).join('')+(active.length>3?'<button id="see-all-competitions">Se alle konkurrencer</button>':''):`<article class="card"><p>Du deltager ikke i en konkurrence endnu.</p><button id="start-first-competition" data-open-competition-creator>Start din første konkurrence</button></article>`; }
function scoreLabel(m){ return {configuredGoals:'Konfigurerede konkurrencemål',goalPercent:'Procent af personligt mål',points:'Samlede aktivitetspoint',baseline:'Forbedring fra egen baseline',raw:'Rå resultater',completedDays:'Antal gennemførte dage'}[m]||m; }
function weightLabel(c){ return c.weighting?.mode==='custom'?Object.entries(c.weighting.weights||{}).map(([id,w])=>`${activityMeta(id).name}: ${w}%`).join(', '):'Lige vægtning'; }
function selfProgressText(c){ if(c.type!=='self') return `Samlet score ${c.results?.userScore||0}`; const rows=(c.activities||[]).map(id=>({id,score:competitionActivityScore(c,id,{id:currentUserId,name:userName()})})).sort((a,b)=>b.score-a.score); return rows[0]?`Din største fremgang er ${activityMeta(rows[0].id).name}. Konsistens tæller mere end perfektion.`:'Klar til start.'; }
function renderCompetitionDetail(){ const arch=$('#archived-competitions'); if(arch) arch.innerHTML=(state.competitions||[]).filter(c=>c.status==='archived'||c.status==='finished').map(c=>`<article class="card"><h3>${c.name}</h3><p>${c.status==='archived'?'Arkiveret':'Afsluttet'} · ${c.finalResults?.[0]?.participant?.name||'Se detaljer'}</p><button data-open-comp="${c.id}">Se detaljer</button></article>`).join('')||'<p class="muted">Ingen tidligere konkurrencer endnu.</p>'; const el=$('#competition-detail'); if(!el) return; const c=state.competitions.find(x=>x.id===selectedCompetitionId); if(!c){ el.innerHTML='<article class="card"><h3>Ingen konkurrence valgt</h3><p>Åbn en konkurrence fra forsiden for at se detaljerne her.</p></article>'; return; } selectedCompetitionId=c.id; const lb=competitionLeaderboard(c,$('#competition-sort')?.value||'score',$('#friends-filter')?.checked); const selfRows=sanitizeActivityIds(c.activities).map(id=>({id,score:competitionActivityScore(c,id,{id:currentUserId,name:userName()}),last:competitionActivityScore(c,id,{id:currentUserId,name:userName()},day(-7))})).sort((a,b)=>b.score-a.score); el.innerHTML=`<article class="card detail-card"><div class="detail-navigation"><button type="button" class="detail-back-button" data-go-home aria-label="Tilbage til forsiden"><span aria-hidden="true">←</span><span>Forside</span></button><span class="detail-navigation-title">Konkurrencedetaljer</span></div><h2>${c.name}</h2><p>${c.status==='finished'?'Tillykke med indsatsen. Sejren er god, men konsistensen er endnu vigtigere.':competitionStatusLine(c)}</p><nav class="tabs"><span>Oversigt</span><span>Stilling</span><span>Aktiviteter</span><span>Deltagere</span><span>Regler</span><span>Ændringslog</span></nav><h3>Oversigt</h3>${competitionCard(c,true)}<h3>Stilling</h3>${c.type==='versus'?`${checkboxRow('id="friends-filter"', 'Vis kun mine venner')}<label class="field">Sortér<select id="competition-sort"><option value="score">Samlet score</option>${sanitizeActivityIds(c.activities).map(id=>`<option value="${id}">${activityMeta(id).name}</option>`).join('')}<option value="completedDays">Gennemførte dage</option><option value="consistency">Konsistens</option><option value="baseline">Forbedring fra baseline</option></select></label><p class="info-box">Leaderboardet bruger demo-deltagere, indtil login og onlinegrupper tilføjes.</p><ol class="leaderboard">${lb.map(r=>`<li class="${r.participant.id===currentUserId?'you':''}"><b>${r.rank}. ${r.participant.name}${c.leaders.includes(r.participant.id)?' · Leder':''}</b><span>${r.score} point · ${r.change>=0?'↗':'↘'} ${Math.abs(r.change)} · ${r.completedDays} dage · streak ${r.streak}</span></li>`).join('')}</ol>`:isCoopCompetition(c)?`<p class="info-box"><b>Sammen mod målet:</b> Alles aktivitet tæller sammen mod ét samlet mål. Her viser vi jeres samlede bidrag som MVP-visning.</p><ol class="leaderboard">${lb.map(r=>`<li class="${r.participant.id===currentUserId?'you':''}"><b>${r.participant.name}</b><span>${r.score} fælles point · ${r.completedDays} dage med bidrag</span></li>`).join('')}</ol>`:`<ol class="leaderboard">${selfRows.map((r,i)=>`<li><b>${i+1}. ${activityMeta(r.id).name}</b><span>${Math.round(r.score/(r.last||100)*100)} % af sidste uge</span></li>`).join('')}</ol><p class="info-box">Denne uge er din 2. bedste af de seneste 8 uger. Du er tæt på din bedste uge.</p>`}<h3>Aktiviteter og regler</h3><div class="chip-row">${Object.keys(activities).map(id=>`${checkboxRow(`data-comp-activity="${id}" ${sanitizeActivityIds(c.activities).includes(id)?'checked':''} ${!isCompetitionLeader(c)?'disabled':''}`, activityMeta(id).name, 'chip')}`).join('')}</div><p>Regelændringer gælder fra ændringstidspunktet. Bagudrettet genberegning kommer senere.</p><h3>Konkurrenceledere</h3><ul class="plain-list">${c.participants.map(p=>`<li>${p.name} ${c.leaders.includes(p.id)?'<span class="leader-badge">Leder</span>':''} ${isCompetitionLeader(c)?`<button data-make-leader="${p.id}">Udnævn</button> <button class="secondary" data-remove-leader="${p.id}">Fjern lederstatus</button>`:''}</li>`).join('')}</ul><h3>Deltagere</h3><ul class="plain-list">${c.participants.map(p=>`<li>${p.name}${p.demo?' · demo-data':''}</li>`).join('')}</ul>${isCompetitionLeader(c)?`<h3>Handlinger for lederen</h3><div class="button-row"><button data-rename-comp="${c.id}">Ændr navn</button><button data-add-demo="${c.id}">Tilføj demo-deltager</button><button class="secondary" data-finish-comp="${c.id}">Afslut konkurrence</button></div>`:''}<h3>Ændringslog</h3><ul class="plain-list">${(c.changeLog||[]).map(l=>`<li>${l.leaderName} ${l.what} den ${new Date(l.at).toLocaleDateString('da-DK')} kl. ${new Date(l.at).toLocaleTimeString('da-DK',{hour:'2-digit',minute:'2-digit'})}. Gammel værdi: ${l.oldValue}. Ny værdi: ${l.newValue}.</li>`).join('')}</ul><div class="button-row"><button data-repeat-comp="${c.id}">Gentag konkurrence</button><button data-clone-comp="${c.id}">Opret ny med samme opsætning</button><button class="secondary" data-archive-comp="${c.id}">Arkivér</button></div></article>`; }
function timeLabel(v){ const total=Math.round(num(v)*60), h=Math.floor(total/60)%24, m=total%60; return `${String(h).padStart(2,'0')}.${String(m).padStart(2,'0')}`; }
function timeInputValue(v){ if(v==null||v==='') return ''; return `${String(Math.floor(num(v))).padStart(2,'0')}:${String(Math.round((num(v)%1)*60)).padStart(2,'0')}`; }
function pickerButton(id,label,value,unit,help='',aria=''){ return `<button type="button" class="value-card" data-open-picker="${id}" aria-label="${aria||label}"><span>${label}</span><strong>${value}</strong><small>${unit}</small></button>${help?`<p class="muted activity-help">${help}</p>`:''}`; }
function stepper(id,cfg,label,unit,min,max,step=1,help=''){ const value=cfg.target??''; return `<div class="ui-card stepper-card" role="group" aria-label="${label}"><span class="goal-input-label">${label}</span><div class="stepper"><button type="button" class="secondary" data-step-goal="${id}" data-delta="-${step}" data-min="${min}" data-max="${max}" aria-label="Sænk ${label}">−</button><label class="stepper-value" aria-label="${label}: ${fmt(value)} ${unit}"><output class="stepper-display" data-stepper-display="${id}" aria-live="polite"><strong data-stepper-number="${id}">${fmt(value)}</strong> <span data-goal-display="${id}">${unit}</span></output><input class="activity-input goal-input-field stepper-input" inputmode="numeric" autocomplete="off" data-integer-input="true" data-goal-field="${id}" data-field="target" data-min="${min}" data-max="${max}" value="${value}" aria-label="${label}"></label><button type="button" class="secondary" data-step-goal="${id}" data-delta="${step}" data-min="${min}" data-max="${max}" aria-label="Hæv ${label}">+</button></div>${help?`<p class="muted activity-help">${help}</p>`:''}</div>`; }
function segmentedControl(id,field,options,value,label='Vælg'){ return `<div class="segmented-control" role="radiogroup" aria-label="${label}">${options.map(([v,t,h])=>`<button type="button" data-goal-segment="${id}" data-field="${field}" data-value="${v}" class="${value===v?'active':''}" aria-pressed="${value===v}"><strong>${t}</strong>${h?`<small data-period-display="${id}">${h}</small>`:''}</button>`).join('')}</div>`; }
function quickChips(id,items){ return `<div class="chip-row quick-row" aria-label="Hurtigvalg">${items.map(([v,t])=>`<button type="button" class="chip quick-chip" data-goal-preset="${id}" data-value="${v}">${t}</button>`).join('')}</div>`; }
function unitInput(id,cfg,label,unit,mode='numeric',help='',attrs=''){ return `<label class="field activity-field goal-input"><span class="goal-input-label">${label}</span><span class="goal-input-wrap"><input class="activity-input activity-number-input goal-input-field" type="text" inputmode="${mode}" autocomplete="off" ${attrs} data-goal-field="${id}" data-field="target" value="${cfg.target??''}" aria-label="${label}"><span class="goal-input-unit">${unit}</span></span></label>${help?`<p class="muted activity-help goal-input-helper">${help}</p>`:''}`; }
function oldGoalNotice(id,cfg,min,max){ return (cfg.migratedFromLegacy===true||cfg.needsReconfiguration===true)?`<p class="error">Kontrollér dette ældre mål</p>`:''; }
function goalEditorHtml(id){ const cfg=draftGoal(id); let body='';
 if(id==='mostSteps') body=`${segmentedControl(id,'period', [['daily','Flest pr. dag','Vind hver dag på flest skridt'],['averageDaily','Højeste gennemsnit','Højeste daglige gennemsnit vinder'],['competition','Hele perioden','Flest skridt samlet']], cfg.period, 'Konkurrencetype for flest skridt')}<p class="info-box">${cfg.period==='averageDaily'?'Vind ved at have det højeste daglige gennemsnit i konkurrenceperioden.':cfg.period==='competition'?'Vind ved at have flest skridt i hele konkurrenceperioden.':'Vind ved at have flest skridt pr. dag.'}</p>`;
 else if(id==='dailyStepTarget') body=`<h5>Dagligt skridtmål</h5>${unitInput(id,cfg,'Dagligt skridtmål','skridt','numeric','Hele tallet er synligt, og hurtigvalg udfylder kun feltet.','data-integer-input="true"')}${quickChips(id,[[5000,'5.000'],[8000,'8.000'],[10000,'10.000'],[12000,'12.000']])}<p class="info-box">Scoring handler om dage, hvor du når dit eget mål.</p>`;
 else if(id==='bedtime') body=`<p class="info-box">Vind ved at gå i seng til tiden.</p><label class="field activity-field goal-input goal-input-time"><span class="goal-input-label">Senest i seng kl.</span><input class="activity-input activity-time-input" type="time" step="300" data-time-field="${id}" data-field="target" value="${timeInputValue(cfg.target)}" aria-label="Senest i seng klokken"></label><p><b>Valgt tidspunkt:</b> kl. ${timeLabel(cfg.target)}</p>`;
 else if(id==='breathing') body=`${pickerButton(id,'Åndedrætsaktiviteter pr. dag',`${fmt(cfg.target||1)} ${(cfg.target||1)===1?'aktivitet':'aktiviteter'}`,`${fmt((cfg.target||1)*10)} åndedrætsrunder pr. dag`,'Tryk for wheel picker, eller brug plus/minus.','Vælg antal åndedrætsaktiviteter')}${stepper(id,cfg,'Antal aktiviteter','aktiviteter',1,10,1,'Én aktivitet svarer til 10 fuldførte åndedrætsrunder.')}${oldGoalNotice(id,cfg,1,10)}`;
 else if(id==='meditation') body=`${quickChips(id,[[5,'5 minutter'],[10,'10 minutter'],[15,'15 minutter'],[20,'20 minutter'],[30,'30 minutter']])}<button type="button" class="secondary" data-open-picker="${id}">Eget mål</button>${pickerButton(id,'Meditation',`${fmt(cfg.target||10)} minutter`,'pr. dag','Vælg 1-120 minutter.')}${stepper(id,cfg,'Meditationsminutter','minutter',1,120,5)}`;
 else if(id==='strength') body=`${segmentedControl(id,'period', [['daily','Dag','pr. dag'],['weekly','Uge','pr. uge'],['competition','Hele perioden','samlet']], cfg.period, 'Periode for styrketræning')}${stepper(id,cfg,'Antal sæt','sæt',1,500,1,'Tryk på tallet for direkte indtastning.')}${oldGoalNotice(id,cfg,1,500)}`;
 else if(id==='running'||id==='cycling') body=kmFields(id,cfg);
 else if(id==='socialMediaFree') body=`<p class="info-box">Jo mindre jo bedre.</p>${segmentedControl(id,'period', [['daily','Pr. dag',''],['averageDaily','Gennemsnit','pr. dag'],['competition','Hele perioden','samlet']], cfg.period, 'Periode for sociale medier')}${quickChips(id,[[15,'15 minutter'],[30,'30 minutter'],[60,'60 minutter'],[90,'90 minutter']])}${pickerButton(id,'Maksimal tid',`Højst ${fmt(cfg.target||0)} minutter`,'pr. dag')}${stepper(id,cfg,'Maksimal tid','minutter',0,360,5)}${oldGoalNotice(id,cfg,0,360)}`;
 else if(id==='screenFreeBeforeBed') body=`${quickChips(id,[[15,'15 minutter'],[30,'30 minutter'],[45,'45 minutter'],[60,'60 minutter']])}${pickerButton(id,'Skærmfri før sengetid',`${fmt(cfg.target||30)} minutter`,'før sengetid')}${stepper(id,cfg,'Minutter før sengetid','minutter',5,180,5)}<p class="info-box">${(competitionDraft.activities||[]).includes('bedtime')?'Beregnes i forhold til dit valgte sengetidsmål.':'Angiv et reference-tidspunkt, hvis Sengetid ikke er valgt.'}</p>${oldGoalNotice(id,cfg,5,180)}`;
 else body=unitInput(id,cfg,'Mål',activities[id]?.unit||'');
 const notice=cfg.migrationNotice?`<p class="info-box">${cfg.migrationNotice}</p>`:''; return `<div class="activity-config" data-activity-editor="${id}"><h4>Vælg mål for denne konkurrence</h4>${body}${notice}</div>`; }
function kmFields(id,cfg){ const presets=id==='running'?[[2,'2 km'],[5,'5 km'],[10,'10 km']]:[[5,'5 km'],[10,'10 km'],[25,'25 km'],[50,'50 km']]; return `${segmentedControl(id,'period', [['daily','Dag','pr. dag'],['weekly','Uge','pr. uge'],['competition','Hele perioden','samlet']], cfg.period, 'Periode for kilometer')}${quickChips(id,presets)}${unitInput(id,cfg,'Antal kilometer','km','decimal','Brug heltal eller én decimal med dansk decimalkomma.','data-decimal-input="true"')}<p class="muted activity-help goal-input-helper">Scores som procent af kilometermålet, maksimum 100 point.</p>`; }

function updateGoalEditorUi(id){ const cfg=draftGoal(id), editor=document.querySelector(`[data-activity-editor="${id}"]`); if(!editor) return; editor.querySelectorAll(`[data-goal-field="${id}"]`).forEach(i=>{ const f=i.dataset.field, next=f==='target'?(cfg.target??''):cfg[f]; if(document.activeElement!==i && next!=null) i.value=next; }); editor.querySelectorAll(`[data-stepper-number="${id}"]`).forEach(el=>{ el.textContent=fmt(cfg.target??0); }); editor.querySelectorAll(`[data-stepper-display="${id}"]`).forEach(el=>{ const unit=el.querySelector(`[data-goal-display="${id}"]`)?.textContent?.trim()||''; el.setAttribute('aria-label', `${fmt(cfg.target??0)} ${unit}`.trim()); const wrap=el.closest('.stepper-value'); if(wrap) wrap.setAttribute('aria-label', `${id}: ${fmt(cfg.target??0)} ${unit}`.trim()); }); editor.querySelectorAll(`[data-goal-segment="${id}"]`).forEach(btn=>{ const active=cfg[btn.dataset.field]===btn.dataset.value; btn.classList.toggle('active',active); btn.setAttribute('aria-pressed',String(active)); }); if(id==='breathing'){ const card=editor.querySelector(`[data-open-picker="${id}"]`); if(card){ card.querySelector('strong').textContent=`${fmt(cfg.target||1)} ${(cfg.target||1)===1?'aktivitet':'aktiviteter'}`; card.querySelector('small').textContent=`${fmt((cfg.target||1)*10)} åndedrætsrunder pr. dag`; }} const text=cfg.complete?goalSummary(cfg):'Ufuldstændig'; const summary=editor.querySelector(`[data-goal-summary="${id}"]`); if(summary) summary.textContent=text; const list=document.querySelector(`[data-activity-list-summary="${id}"]`); if(list) list.textContent=cfg.complete?goalSummary(cfg):'Ufuldstændig – vælg mål for denne konkurrence'; updateWizardValidation(); }
function updateWizardValidation(){ const d=competitionDraft; if(!d) return; const incomplete=wizardIncompleteActivities(d), validation=$('#activity-validation'), next=$('#wizard-next'); if(validation){ validation.textContent=!d.activities.length?'Vælg mindst én aktivitet.':incomplete.length?'Vælg mål for alle aktiviteter.':'Alle valgte aktiviteter er konfigureret.'; validation.className=!d.activities.length||incomplete.length?'error':'muted'; } if(next) next.disabled=!!(!d.activities.length||incomplete.length); }
function activityOptionHtml(id){ const a=activities[id], selected=competitionDraft.activities.includes(id), cfg=(competitionDraft.activityGoals||{})[id]; return `<article class="competition-activity-option ${selected?'selected':''}" data-activity-option="${id}"><input data-draft-activity="${id}" type="checkbox" ${selected?'checked':''}><span class="activity-icon">${a.icon}</span><span class="activity-content"><strong>${a.name}</strong><span>${a.description}</span>${selected?`<small data-activity-list-summary="${id}">${cfg?.complete?goalSummary(cfg):'Ufuldstændig – vælg mål for denne konkurrence'}</small>`:''}</span>${selected?goalEditorHtml(id):''}</article>`; }
function bindGoalControls(container=document,step=1){ const q=s=>Array.from(container.querySelectorAll(s)); q('[data-goal-preset]').forEach(b=>b.onclick=e=>{ consumeInteraction(e); const cfg=draftGoal(b.dataset.goalPreset); cfg.target=num(b.dataset.value); cfg.unit=metricUnits[cfg.metric]||cfg.unit; cfg.legacyDefault=false; cfg.complete=goalComplete(cfg); updateGoalEditorUi(b.dataset.goalPreset); }); q('[data-step-goal]').forEach(b=>b.onclick=e=>{ consumeInteraction(e); const id=b.dataset.stepGoal, cfg=draftGoal(id), min=num(b.dataset.min), max=num(b.dataset.max), delta=Number(b.dataset.delta)||1; const raw = Number(cfg.target); const current = Number.isFinite(raw) ? raw : min; const next = clamp(current + delta, min, max); setDraftGoalValue(id,next,'target',min,max); updateGoalEditorUi(id); }); q('[data-goal-segment]').forEach(b=>b.onclick=e=>{ consumeInteraction(e); const cfg=draftGoal(b.dataset.goalSegment); cfg[b.dataset.field]=b.dataset.value; cfg.legacyDefault=false; cfg.complete=goalComplete(cfg); updateGoalEditorUi(b.dataset.goalSegment); }); q('[data-open-picker]').forEach(b=>b.onclick=e=>{ consumeInteraction(e); openGoalPicker(b.dataset.openPicker,step); }); q('[data-time-field]').forEach(i=>i.onchange=()=>{ const cfg=draftGoal(i.dataset.timeField), [h,m]=(i.value||'00:00').split(':').map(Number); cfg[i.dataset.field]=h+(m||0)/60; cfg.legacyDefault=false; cfg.complete=goalComplete(cfg); updateGoalEditorUi(i.dataset.timeField); }); q('[data-use-personal-goal]').forEach(b=>b.onclick=e=>{ consumeInteraction(e); const cfg=draftGoal(b.dataset.usePersonalGoal); cfg.target=goalFor(b.dataset.usePersonalGoal); cfg.legacyDefault=false; cfg.complete=goalComplete(cfg); updateGoalEditorUi(b.dataset.usePersonalGoal); }); q('[data-custom-goal]').forEach(b=>b.onclick=e=>{ consumeInteraction(e); const v=prompt('Eget mål',''); if(v!==null){ const cfg=draftGoal(b.dataset.customGoal); cfg.target=num(v); cfg.legacyDefault=false; cfg.complete=goalComplete(cfg); updateGoalEditorUi(b.dataset.customGoal); }}); q('[data-integer-input]').forEach(i=>i.oninput=()=>{ const clean=i.value.replace(/\D/g,''); if(i.value!==clean) i.value=clean; }); q('[data-decimal-input]').forEach(i=>i.oninput=()=>{ let clean=i.value.replace(',', '.').replace(/[^0-9.]/g,''); const parts=clean.split('.'); if(parts.length>2) clean=`${parts.shift()}.${parts.join('')}`; if(i.value!==clean) i.value=clean; }); q('[data-goal-field]').forEach(i=>{ i.onchange=()=>{ if(i.dataset.integerInput==='true') i.value=i.value.replace(/\D/g,''); if(i.dataset.decimalInput==='true'){ let clean=i.value.replace(',', '.').replace(/[^0-9.]/g,''); const parts=clean.split('.'); if(parts.length>2) clean=`${parts.shift()}.${parts.join('')}`; i.value=clean; } const cfg=draftGoal(i.dataset.goalField), f=i.dataset.field; if(f==='target'||f==='bonusTarget'||f==='tolerance') cfg[f]=i.value===''?null:num(i.value); else if(f==='bedtimeStart'||f==='bedtimeEnd'){ cfg.bedtimeWindow ||= {}; cfg.bedtimeWindow[f==='bedtimeStart'?'start':'end']=i.value; } else cfg[f]=i.value; if(f==='metric') cfg.unit=metricUnits[cfg.metric]||cfg.unit; cfg.legacyDefault=false; cfg.complete=goalComplete(cfg); updateGoalEditorUi(i.dataset.goalField); }; i.oninput=i.onchange; }); q('[data-custom-time]').forEach(b=>b.onclick=e=>{ consumeInteraction(e); const v=prompt('Eget tidspunkt (HH:MM)','22:30'); if(v){ const [h,m]=v.split(':').map(Number); const cfg=draftGoal(b.dataset.customTime); cfg.target=h+(m||0)/60; cfg.legacyDefault=false; cfg.complete=goalComplete(cfg); updateGoalEditorUi(b.dataset.customTime); }}); q('[data-sleep-criterion]').forEach(i=>i.onchange=()=>{ const cfg=draftGoal(i.dataset.sleepCriterion); const vals=Array.from(container.querySelectorAll('[data-sleep-criterion]')).filter(x=>x.checked).map(x=>x.value); cfg.criteria=vals; cfg.comparisonMode='withinRange'; cfg.complete=goalComplete(cfg); updateGoalEditorUi(i.dataset.sleepCriterion); }); }
function updateActivityOption(id,step){ const currentCard=document.querySelector(`[data-activity-option="${id}"]`); if(!currentCard) return; const wrapper=document.createElement('div'); wrapper.innerHTML=activityOptionHtml(id).trim(); const newCard=wrapper.firstElementChild; currentCard.replaceWith(newCard); bindActivityOption(newCard,step); updateWizardValidation(); }
function bindActivityOption(card,step){ const checkbox=card.querySelector('[data-draft-activity]'); if(checkbox){ checkbox.onchange=event=>{ event.stopPropagation(); const id=checkbox.dataset.draftActivity; if(checkbox.checked){ competitionDraft.activities=[...new Set([...competitionDraft.activities,id])]; draftGoal(id); } else { competitionDraft.activities=competitionDraft.activities.filter(activityId=>activityId!==id); delete competitionDraft.activityGoals?.[id]; } competitionDraft.weights=defaultWeights(competitionDraft.activities); updateActivityOption(id,step); saveCompetitionDraft(); }; } card.onclick=event=>{ if(event.target.closest('.activity-config, button, input, select, label')) return; const box=card.querySelector('[data-draft-activity]'); if(box){ box.checked=!box.checked; box.dispatchEvent(new Event('change',{bubbles:false})); } }; bindGoalControls(card,step); }
function renderWizardPreservingScroll(step){ const card=$('#competition-wizard')?.querySelector?.('.modal-card'), top=card?.scrollTop||0; renderWizard(step); const next=$('#competition-wizard')?.querySelector?.('.modal-card'); if(next) next.scrollTop=top; }
